      logger.info('Migration v4: Created FSRS indexes');
    },
    5: () => {
      // V4 -> v5: Add memory_type column for type-specific half-lives
      try {
        database.exec(`
          ALTER TABLE memory_index ADD COLUMN memory_type TEXT DEFAULT 'declarative'
